                    Text(title)
                        .padding()
                        .frame(maxWidth: .infinity)
                        .background(theme.backgroundColor)
                        .foregroundColor(theme.foregroundColor)
                        .cornerRadius(10)
                }
            )
        )
    }
}

class ThemedText: ThemedComponent {
    let theme: Theme
    let text: String

    init(theme: Theme, text: String) {
        self.theme = theme
        self.text = text
    }

    func renderView() -> AnyView {
        AnyView(
